fn print_boot_splash(hart_id: usize, hart_count: usize) {
    const LOGO: [&str; 7] = [
        "        ______                    ____   _____                  ",
        "       / ____/___  _________ ___ / __ \\ / ___/                  ",
        "      / /   / __ \\/ ___/ __ `__ \\/ / / /\\__ \\                 ",
        "     / /___/ /_/ (__  ) / / / / / /_/ /___/ /                  ",
        "     \\____/\\____/____/_/ /_/ /_/\\____//____/                   ",
        "                            CosmOS                              ",
        "              a small universe in supervisor mode               ",
    ];

    println!("");
    println!(
        "{frame}+------------------------------------------------------------------+{reset}",
        frame = ANSI_FRAME,
        reset = ANSI_RESET,
    );
    for line in LOGO {
        println!(
            "{frame}|{reset} {title}{line:<66}{reset} {frame}|{reset}",
            frame = ANSI_FRAME,
            title = ANSI_TITLE,
            line = line,
            reset = ANSI_RESET,
        );
    }
    println!(
        "{frame}|{reset} {subtitle}{msg:<66}{reset} {frame}|{reset}",
        frame = ANSI_FRAME,
        subtitle = ANSI_SUBTITLE,
        msg = "CosmOS boot sequence engaged",
        reset = ANSI_RESET,
    );
    println!(
        "{frame}|{reset} {subtitle}{msg:<66}{reset} {frame}|{reset}",
        frame = ANSI_FRAME,
        subtitle = ANSI_SUBTITLE,
        msg = format_args!("Bootstrap hart #{hart_id} | {hart_count}-core startup"),
        reset = ANSI_RESET,
    );
    println!(
        "{frame}|{reset} {subtitle}{msg:<66}{reset} {frame}|{reset}",
        frame = ANSI_FRAME,
        subtitle = ANSI_SUBTITLE,
        msg = format!(
            "Target: {} - {}",
            crate::platform::machine_name(),
            crate::platform::platform_name()
        ),
        reset = ANSI_RESET,
    );
    println!(
        "{frame}+------------------------------------------------------------------+{reset}",
        frame = ANSI_FRAME,
        reset = ANSI_RESET,
    );
    println!("");
}

