/// 将 HSM 原始状态值转换为可读枚举。
pub fn hart_state(raw: usize) -> HartState {
    match raw {
        0 => HartState::Started,
        1 => HartState::Stopped,
        2 => HartState::StartPending,
        3 => HartState::StopPending,
        4 => HartState::Suspended,
        5 => HartState::SuspendPending,
        6 => HartState::ResumePending,
        other => HartState::Unknown(other),
    }
}

